fn k_str(keys: &[String], i: usize) -> crate::Result<&str> {
    keys.get(i).map(String::as_str)
        .ok_or_else(|| crate::Error::Odb(format!("missing key #{i}")))
}
fn k_idx(keys: &[String], i: usize) -> crate::Result<usize> {
    k_str(keys, i)?.parse()
        .map_err(|_| crate::Error::Odb(format!("key #{i} must be an integer index")))
}

