#[cfg(feature = "gen-write")]
fn val(values: &[String], j: usize) -> crate::Result<&str> {
    values.get(j).map(String::as_str)
        .ok_or_else(|| crate::Error::Odb(format!("missing value #{j}")))
}

/// Apply a setter by (class, field) with string keys + string-encoded values.
#[cfg(feature = "gen-write")]
